/* com.erns.coching.raw.mapper.RawDAO.load */
SELECT
, FI.FILE_ID , RSUB.RAW_SUB_SEQ , RSUB.RAW_SUB_NAME_KO , RSUB.RAW_SUB_INCI , RSUB.CAS_NO , RCOD.DOC_CODE , RCOD.DOC_FILE_ID , RTYPE.GRP_CODE , RTYPE.CODE FROM T_RAW_MST AA LEFT JOIN T_FILE_INF FI ON AA.FILE_ID = FI.FILE_ID LEFT JOIN T_RAW_SUB_INF RSUB ON AA.RAW_SEQ = RSUB.RAW_SEQ LEFT JOIN T_RAW_DOC RCOD ON AA.RAW_SEQ = RCOD.RAW_SEQ LEFT JOIN T_RAW_TYPE_INF RTYPE ON AA.RAW_SEQ = RTYPE.RAW_SEQ

mapper.insert:
    	/* com.erns.coching.raw.mapper.RawDAO.insert */


			SELECT nextval('seq_t_raw_mst')


    	INSERT INTO T_RAW_MST (
    		  RAW_SEQ
			, RAW_NAME
			, RAW_MEMB
			, PROD_COMPANY
			, PROD_COUNTRY
			, SUPPLIER
			, FILE_ID
			, RAW_DESC
			, REQUEST_CNT
			, USE_YN
			, DEL_YN
			, PERMIT_YN
			, RGTR
			, RGT_DTTM
    	) VALUES (
			  #{rawSeq		, jdbcType=INTEGER}
			, #{rawName		, jdbcType=VARCHAR}
			, #{rawMemb		, jdbcType=INTEGER}
			, #{prodCompany	, jdbcType=VARCHAR}
			, #{prodCountry	, jdbcType=VARCHAR}
			, #{supplier	, jdbcType=VARCHAR}
			, #{fileId		, jdbcType=VARCHAR}
			, #{rawDesc		, jdbcType=VARCHAR}
			, #{requestCnt	, jdbcType=INTEGER}
			, COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')
			, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
			, #{permitYn	, jdbcType=CHAR}
			, #{rgtr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.raw.mapper.RawDAO.update */

    	UPDATE T_RAW_MST SET
			  RAW_NAME       		= #{rawName		, jdbcType=VARCHAR}
			, RAW_MEMB       		= #{rawMemb		, jdbcType=INTEGER}
			, PROD_COMPANY        	= #{prodCompany	, jdbcType=VARCHAR}
			, PROD_COUNTRY        	= #{prodCountry	, jdbcType=VARCHAR}
			, SUPPLIER        		= #{supplier	, jdbcType=VARCHAR}
			, RAW_DESC        		= #{rawDesc	, jdbcType=VARCHAR}
			, USE_YN            	= COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')
			, DEL_YN            	= COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
			, PERMIT_YN            	= #{permitYn	, jdbcType=CHAR}

			, CHNR 		 		= #{chnr, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			AND RAW_SEQ 		= #{rawSeq	, jdbcType=INTEGER}

    	/* com.erns.coching.raw.mapper.RawDAO.updateUseYn */

    	UPDATE T_RAW_MST SET
			  USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			AND RAW_SEQ 		= #{rawSeq	, jdbcType=INTEGER}

    	/* com.erns.coching.raw.mapper.RawDAO.updateDelYn */

    	UPDATE T_RAW_MST SET
			  DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			AND RAW_SEQ 		= #{rawSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.updateDetailViewCnt */

UPDATE T_RAW_DETAIL SET
	VIEW_CNT      			= VIEW_CNT + 1

	AND RAW_DETAIL_SEQ = #{value, jdbcType=INTEGER}

    	/* com.erns.coching.raw.mapper.RawDAO.updateRequestCnt */

    	UPDATE T_RAW_DETAIL SET
    		  REQUEST_CNT 		= REQUEST_CNT + 1

			AND RAW_SEQ 		= #{rawSeq	, jdbcType=INTEGER}
			AND MEMB_SEQ		= #{membSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.raw.mapper.RawDAO.delete */

DELETE FROM T_RAW_MST

	AND RAW_SEQ 	= #{rawSeq	, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.raw.mapper.RawDAO.getDetail */ SELECT
FROM T_RAW_DETAIL FF INNER JOIN T_RAW_MANAGER EE ON EE.RAW_SEQ = FF.RAW_SEQ AND EE.MEMB_SEQ = FF.MEMB_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ
AND FF.RAW_DETAIL_SEQ = #{rawDetailSeq, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getRequestList */
SELECT B.* FROM ( SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM ( SELECT
, , , PP.PTN_NAME , MI.MEMB_NAME AS MANAGER_NAME FROM T_RAW_REQUEST RR INNER JOIN T_RAW_DETAIL FF ON FF.RAW_DETAIL_SEQ = RR.RAW_DETAIL_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ INNER JOIN T_PARTNER_INF PP ON AA.PTN_SEQ = PP.PTN_SEQ INNER JOIN T_MEMB_INF MI ON FF.MEMB_SEQ = MI.MEMB_SEQ
AND RR.RGTR = #{membSeq , jdbcType=INTEGER}
AND FF.MEMB_SEQ = #{managerSeq , jdbcType=INTEGER}
AND PP.PTN_SEQ = #{ptnSeq , jdbcType=INTEGER}
ORDER BY RR.RGT_DTTM DESC ) A ) B
WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.raw.mapper.RawDAO.getRequestListCount */
SELECT COUNT(*) FROM T_RAW_REQUEST RR INNER JOIN T_RAW_DETAIL FF ON FF.RAW_DETAIL_SEQ = RR.RAW_DETAIL_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ INNER JOIN T_PARTNER_INF PP ON AA.PTN_SEQ = PP.PTN_SEQ INNER JOIN T_MEMB_INF MI ON FF.MEMB_SEQ = MI.MEMB_SEQ
AND RR.RGTR = #{membSeq , jdbcType=INTEGER}
AND FF.MEMB_SEQ = #{managerSeq , jdbcType=INTEGER}
AND PP.PTN_SEQ = #{ptnSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.loadRequest */
SELECT
, , , MI.MEMB_NAME AS MEMB_NAME , MI.PTN_SEQ AS PTN_SEQ , MI2.MEMB_NAME AS MANAGER_NAME , MI2.PTN_SEQ AS MANAGER_PTN_SEQ FROM T_RAW_REQUEST RR INNER JOIN T_RAW_DETAIL FF ON FF.RAW_DETAIL_SEQ = RR.RAW_DETAIL_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ INNER JOIN T_PARTNER_INF PP ON AA.PTN_SEQ = PP.PTN_SEQ INNER JOIN T_MEMB_INF MI ON MI.MEMB_SEQ = RR.RGTR INNER JOIN T_MEMB_INF MI2 ON MI2.MEMB_SEQ = FF.MEMB_SEQ
RR.RAW_REQUEST_SEQ = #{rawRequestSeq , jdbcType=INTEGER}
AND RR.RGTR = #{membSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getRequestTypeList */
SELECT RT.CODE FROM T_RAW_REQUEST_TYPE RT INNER JOIN T_RAW_REQUEST RR ON RT.RAW_REQUEST_SEQ = RR.RAW_REQUEST_SEQ
RT.RAW_REQUEST_SEQ = #{rawRequestSeq , jdbcType=INTEGER}

