/* com.erns.coching.raw.mapper.RawDAO.insertRequest */


	SELECT nextval('seq_t_raw_request')


INSERT INTO T_RAW_REQUEST (
    RAW_REQUEST_SEQ
	, RAW_DETAIL_SEQ
	, PTN_SEQ
	, PTN_NAME
	, PHONE
	, EMAIL
	, ADDRESS
	, REQ_DETAIL
	, MESSAGE_TYPE
	, RGTR
	, RGT_DTTM
) VALUES (
	#{rawRequestSeq		, jdbcType=INTEGER}
	, #{rawDetailSeq	, jdbcType=INTEGER}
	, #{ptnSeq			, jdbcType=INTEGER}
	, #{ptnName			, jdbcType=VARCHAR}
	, #{phone			, jdbcType=VARCHAR}
	, #{email			, jdbcType=VARCHAR}
	, #{address			, jdbcType=VARCHAR}
	, #{reqDetail		, jdbcType=VARCHAR}
	, #{messageType		, jdbcType=VARCHAR}
	, #{rgtr			, jdbcType=INTEGER}
	, now()
)

		/* com.erns.coching.raw.mapper.RawDAO.insertRequestType */

		INSERT INTO T_RAW_REQUEST_TYPE (
			RAW_REQUEST_SEQ
			, CODE
			, RGTR
			, RGT_DTTM
		) VALUES (
			#{rawRequestSeq	, jdbcType=INTEGER}
			, #{code	, jdbcType=VARCHAR}
			, #{rgtr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
/* com.erns.coching.raw.mapper.RawDAO.updateStatus */

UPDATE T_RAW_REQUEST SET
status            = #{status	, jdbcType=CHAR}

, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
, CHNG_DTTM  		= now()

	AND RAW_REQUEST_SEQ 		= #{rawRequestSeq	, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.raw.mapper.RawDAO.insertRequestReply */


	SELECT
	nextval('seq_t_raw_request_reply') AS rawReplySeq,
	COALESCE(
	(SELECT COUNT(*)
	FROM T_RAW_REQUEST_REPLY
	WHERE RAW_REQUEST_SEQ = #{rawRequestSeq}
	AND REF_SEQ = #{refSeq}), 1) AS replyCmtOrd


INSERT INTO T_RAW_REQUEST_REPLY (
	 RAW_REPLY_SEQ
	, RAW_REQUEST_SEQ
   	, DISPATCH_CODE
   	, DISPATCH_DATE
   	, CONTENTS
   	, REF_SEQ
   	, REPLY_CMT_ORD
   	, RGTR
   	, RGT_DTTM
) VALUES (
	#{rawReplySeq		, jdbcType=INTEGER}
	, #{rawRequestSeq	, jdbcType=INTEGER}
	, #{dispatchCode	, jdbcType=VARCHAR}
	, #{dispatchDate	, jdbcType=VARCHAR}
	, #{contents		, jdbcType=VARCHAR}
	, #{refSeq			, jdbcType=INTEGER}
	, #{replyCmtOrd		, jdbcType=INTEGER}
	, #{rgtr			, jdbcType=INTEGER}
	, now()
)

mapper.update:
	/* com.erns.coching.raw.mapper.RawDAO.updateReply */

	UPDATE T_RAW_REQUEST_REPLY SET
	content 			= #{contents		, jdbcType=VARCHAR}
 	, dispatch_date		= #{dispatchDate	, jdbcType=VARCHAR}

	, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

		AND RAW_REPLY_SEQ 		= #{rawReplySeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.updateReplyDelYn */

UPDATE T_RAW_REQUEST_REPLY SET
	del_yn            = #{delYn		, jdbcType=CHAR}

	, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND RAW_REPLY_SEQ 		= #{rawReplySeq	, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.raw.mapper.RawDAO.getCmTypeList */ SELECT GRP_CODE, CODE, CODE_NM_KO, CODE_NM_EN, INPT_TYPE, SORT_ORD FROM T_CM_RAW_TYPE
